<?php require "conn.php"; $test=0; $UserLat = isset($_POST["UserLat"]) ? (float)$_POST["UserLat"] : 0.0; $UserLongt = isset($_POST["UserLongt"]) ? (float)$_POST["UserLongt"] : 0.0; $UserID = $_POST["UserID"] ?? 0; $BoostPage = 0; $Page = $_POST["Page"] ?? 0; $Pro = $_POST["Pro"] ?? "Normal"; $BoostPage = $Page * 2; $PageBoost = $Page; if($Page==""){ $Page =0; }else{ $Page = $Page * 5; } if($Pro==""){ $Pro = "Normal"; } $res = mysqli_query($con,"SELECT * FROM Posts JOIN Shops ON Posts.ShopID=Shops.ShopID LEFT JOIN Foods ON Posts.ProductID=Foods.FoodID WHERE Shops.Status = 'ACTIVE' AND Posts.PostStatus='ACTIVE' AND (Posts.Video IS NULL OR Posts.Video = '' OR Posts.Video = '0' OR Posts.Video = 'NONE')"); $res = mysqli_query($con," SELECT Shops.*, Posts.*, Foods.*, (6372.797 * acos(cos(radians($UserLat)) * cos(radians(ShopLat)) * cos(radians(ShopLongt) - radians($UserLongt)) + sin(radians($UserLat)) * sin(radians(ShopLat)))) AS distance FROM Shops JOIN Posts ON Shops.ShopID=Posts.ShopID LEFT JOIN Foods ON Posts.ProductID = Foods.FoodID JOIN Categories ON Shops.CategoryID = Categories.CategoryId WHERE Shops.Status = 'ACTIVE' AND Categories.Pro = '$Pro' AND Posts.PostStatus='ACTIVE' AND (Posts.Video IS NULL OR Posts.Video = '' OR Posts.Video = '0' OR Posts.Video = 'NONE') HAVING distance <= 10050 ORDER BY distance ASC, (Posts.PostLikes * 2 + Posts.Postcomments * 3) DESC, rand() LIMIT $Page, 5 "); $result = array(); $i = 0; while($row = mysqli_fetch_assoc($res)){ $result[] = $row; $test = 4; } if($test==4){ echo "OK"; } else { echo "NO"; } ?>
